package com.oneil.wellness.walkplanner.history;
import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;import java.time.*;import java.util.*;import org.junit.jupiter.api.Test;
class RecommendationHistoryServiceTest{
 @Test void persistsOnlyMeaningfulChanges(){HistoryRepository repository=mock(HistoryRepository.class);var service=new RecommendationHistoryService(repository);var first=snapshot(80,"2026-07-20T14:00:00Z",true);when(repository.findTopByOrderByCapturedAtDesc()).thenReturn(Optional.empty(),Optional.of(new RecommendationHistory(first)),Optional.of(new RecommendationHistory(first)));service.record(first);service.record(snapshot(81,"2026-07-20T14:00:00Z",true));service.record(snapshot(85,"2026-07-20T14:00:00Z",true));verify(repository,times(2)).save(any());}
 @Test void generatesSummaryAndSignificantComparison(){HistoryRepository repository=mock(HistoryRepository.class);var first=snapshot(91,"2026-07-20T14:00:00Z",true);var second=new RecommendationSnapshot(Instant.now(),82,OffsetDateTime.parse("2026-07-20T15:00:00Z"),OffsetDateTime.parse("2026-07-20T15:30:00Z"),71d,12d,40d,20d,6d,false,List.of("CALDAV"),"Wind increased.");when(repository.findByCapturedAtAfterOrderByCapturedAtAsc(any())).thenReturn(List.of(new RecommendationHistory(first),new RecommendationHistory(second)));var result=new RecommendationHistoryService(repository).history();assertEquals(2,result.week().opportunities()+result.week().missedOpportunities());assertEquals(-9,result.comparison().scoreDifference());assertTrue(result.comparison().significantReasons().contains("Higher wind"));assertTrue(result.week().providerSources().containsAll(List.of("MANUAL","CALDAV")));}
 private RecommendationSnapshot snapshot(int score,String start,boolean available){OffsetDateTime time=OffsetDateTime.parse(start);return new RecommendationSnapshot(Instant.now(),score,time,time.plusMinutes(30),71d,4d,48d,20d,2d,available,List.of("MANUAL"),"Temperature ideal.");}
}
